-- 외부 파일 데이터용 디렉토리 객체 생성
CREATE OR REPLACE DIRECTORY ext_data_dir
  AS '/u01/app/oracle/external_data';

-- 로그 파일용 디렉토리 객체 생성
CREATE OR REPLACE DIRECTORY ext_log_dir
  AS '/u01/app/oracle/external_logs';

-- 전처리기(Preprocessor)용 디렉토리 객체 생성
CREATE OR REPLACE DIRECTORY ext_exec_dir
  AS '/usr/bin';

-- HR 사용자에게 읽기/쓰기 권한 부여
GRANT READ, WRITE ON DIRECTORY ext_data_dir TO hr;
GRANT READ, WRITE ON DIRECTORY ext_log_dir TO hr;
GRANT EXECUTE ON DIRECTORY ext_exec_dir TO hr;

-- 외부 테이블 통계정보 수집
BEGIN
    DBMS_STATS.GATHER_TABLE_STATS(
        ownname => 'HR',
        tabname => 'EXT_EMPLOYEES',
        degree  => 4
    );
END;
/

-- 외부 테이블의 병렬도 변경
ALTER TABLE hr.ext_employees PARALLEL 4;

-- 외부 테이블의 접근 파라미터 변경
ALTER TABLE hr.ext_employees
    ACCESS PARAMETERS (
        RECORDS DELIMITED BY NEWLINE
        FIELDS TERMINATED BY '|'
        MISSING FIELD VALUES ARE NULL
    );

-- 외부 테이블 파일 위치 변경
ALTER TABLE hr.ext_employees
    LOCATION ('new_employees_2026.csv');

-- 외부 테이블 REJECT LIMIT 변경
ALTER TABLE hr.ext_employees REJECT LIMIT UNLIMITED;
